import{_ as t,o,c as a,a2 as n}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"Integrations & Webhooks","description":"","frontmatter":{},"headers":[],"relativePath":"app/integrations.md","filePath":"app/integrations.md"}'),r={name:"app/integrations.md"};function i(s,e,d,h,l,c){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="integrations-webhooks" tabindex="-1">Integrations &amp; Webhooks <a class="header-anchor" href="#integrations-webhooks" aria-label="Permalink to &quot;Integrations &amp; Webhooks&quot;">​</a></h1><p>Integrations connect your version control system (VCS) to Tragwerk so that a <code>git push</code> automatically triggers a build and deployment. Each project has its own webhook integration with a unique signing secret.</p><h2 id="creating-a-webhook-integration" tabindex="-1">Creating a webhook integration <a class="header-anchor" href="#creating-a-webhook-integration" aria-label="Permalink to &quot;Creating a webhook integration&quot;">​</a></h2><p>Open <strong>Integrations</strong> for the active project and choose <strong>Create integration</strong>. You select the VCS provider that hosts the repository; Tragwerk generates a random signing secret and exposes a VCS-specific receiver endpoint.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Only <strong>one</strong> webhook integration may exist per project at a time. Delete the existing integration before creating a new one.</p></div><p>Supported version control system providers:</p><table tabindex="0"><thead><tr><th>Provider</th><th>Route slug</th></tr></thead><tbody><tr><td>GitHub</td><td><code>github</code></td></tr><tr><td>GitLab</td><td><code>gitlab</code></td></tr><tr><td>Forgejo</td><td><code>forgejo</code></td></tr><tr><td>Gitea</td><td><code>gitea</code></td></tr><tr><td>Codeberg</td><td><code>codeberg</code></td></tr><tr><td>Bitbucket</td><td><code>bitbucket</code></td></tr></tbody></table><p>After creating the integration, copy the endpoint URL and secret into your VCS provider&#39;s webhook settings (push events only).</p><h3 id="vcs-endpoint" tabindex="-1">VCS endpoint <a class="header-anchor" href="#vcs-endpoint" aria-label="Permalink to &quot;VCS endpoint&quot;">​</a></h3><p>Each integration is served at:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /webhooks/{forge}/{projectId}</span></span></code></pre></div><p>For example, a GitHub integration for project <code>abc123</code> is reached at <code>https://your-tragwerk-host/webhooks/github/abc123</code>. The handler:</p><ol><li>Resolves the VCS provider from the route slug and loads the project.</li><li>Looks up the project&#39;s stored integration secret.</li><li>Verifies the request signature against that secret (returns <code>401</code> on mismatch).</li><li>Extracts the push payload (branch + commit SHA).</li><li>Dispatches a build for that branch, or — when the push deletes a branch — tears down the matching <a href="/app/environments">environment</a>.</li></ol><h3 id="deleting-an-integration" tabindex="-1">Deleting an integration <a class="header-anchor" href="#deleting-an-integration" aria-label="Permalink to &quot;Deleting an integration&quot;">​</a></h3><p>On the <strong>Integrations</strong> page, use <strong>Delete</strong> next to the integration. This removes the secret and disables the receiver endpoint; existing deployments are not affected.</p><h2 id="example-wiring-up-github" tabindex="-1">Example: wiring up GitHub <a class="header-anchor" href="#example-wiring-up-github" aria-label="Permalink to &quot;Example: wiring up GitHub&quot;">​</a></h2><ol><li>In Tragwerk, open <strong>Integrations</strong> and create a <strong>GitHub</strong> integration.</li><li>Copy the endpoint URL (<code>/webhooks/github/{projectId}</code>) and the generated secret.</li><li>In GitHub, go to <strong>Settings → Webhooks → Add webhook</strong>.</li><li>Set the <strong>Payload URL</strong> to the Tragwerk endpoint, <strong>Content type</strong> to <code>application/json</code>, paste the <strong>Secret</strong>, and select <strong>Just the push event</strong>.</li><li>Push a commit — Tragwerk verifies the signature and starts a <a href="/app/deployments">deployment</a>.</li></ol><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/app/projects">Projects</a></li><li><a href="/app/environments">Environments</a></li><li><a href="/app/deployments">Deployments</a></li></ul>',19)])])}const u=t(r,[["render",i]]);export{g as __pageData,u as default};
